import{_ as i,o as t,c as s,a2 as n}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Onboarding & Fonctionnement","description":"","frontmatter":{"title":"Onboarding & Fonctionnement"},"headers":[],"relativePath":"docs/fr/publishers/onboarding-process.md","filePath":"docs/fr/publishers/onboarding-process.md"}'),o={name:"docs/fr/publishers/onboarding-process.md"};function r(a,e,l,d,p,c){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="onboarding-et-fonctionnement" tabindex="-1">Onboarding et Fonctionnement <a class="header-anchor" href="#onboarding-et-fonctionnement" aria-label="Permalink to &quot;Onboarding et Fonctionnement&quot;">​</a></h1><p>Bienvenue sur getinside ! Ne vous contentez pas d&#39;attendre les campagnes : prenez le contrôle de votre régie, activez vos partenaires historiques et maximisez vos revenus.</p><hr class="my-6"><h2 class="text-purple-200 mb-6">Phase 1 : Configuration et Activation</h2><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-grey-dk-000">Démo &amp; Création du compte</h3><p>Tout commence par un call de démo avec l&#39;équipe getinside.</p><ul><li>L&#39;équipe crée votre compte e-commerçant.</li><li>Tous les contacts fournis reçoivent un email d&#39;invitation.</li><li><strong>Action :</strong> Cliquez sur le lien dans l&#39;email pour créer votre mot de passe et accéder à la plateforme.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3 class="mt-0 text-grey-dk-000">Configuration Logistique</h3><p>Avant de créer vos audiences, définissez vos contraintes logistiques (indispensable pour l&#39;algorithme).</p><div style="background:var(--vp-c-bg-soft);padding:15px;border-radius:6px;border-left:4px solid #2563eb;"><strong>📍 Adresse de l&#39;entrepôt :</strong> Lieu de livraison des supports.<br><strong>⏱️ Délai d&#39;ingestion (Lead Time) :</strong> Délai minimum entre la livraison et le début de la diffusion (automatiquement pris en compte par la plateforme). </div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3 class="mt-0 text-grey-dk-000">Création des Audiences</h3><p>Dans l&#39;onglet <strong>Monétisation</strong>, l&#39;équipe e-commerçant crée ses audiences.</p><div style="margin-top:10px;"><a href="audience-setup" class="btn btn-outline btn-sm">Voir le guide détaillé de la Fiche Audience &amp; Score →</a></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">4</div><div><h3 class="mt-0 text-grey-dk-000">Ajout des Types de Campagnes</h3><p>Pour chaque audience créée, ajoutez les types de campagnes acceptés et leurs critères :</p><ul><li><strong>📦 Asile Colis :</strong> Capacité (max flyers simultanés), formats acceptés, volumes prévisionnels par semaine sur 12 mois.</li><li><strong>📧 Digital :</strong> CPM indicatif, exemples de campagnes passées, infos de performance (Taux d&#39;ouverture, Clics).</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">5</div><div><h3 class="mt-0 text-grey-dk-000">Validation (Call de contrôle)</h3><p>Dès que vous estimez avoir complété les infos, avertissez l&#39;équipe getinside.</p><ul><li>Nous proposons un call pour confirmer que toutes les infos nécessaires sont remplies.</li><li>Rappel des aspects techniques et des bonnes pratiques.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#28a745;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">✓</div><div><h3 class="mt-0 text-green-200">Activation</h3><p>Suite au call :</p><ul><li>✅ Les audiences et types de campagnes validés sont <strong>activés</strong>.</li><li>⏸️ Ceux qui sont incomplets restent non-référencés en attendant.</li></ul></div></div><hr class="my-6"><h2 class="text-purple-200 mb-6">Phase 2 : Gestion des Campagnes</h2><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">7</div><div><h3 class="mt-0 text-grey-dk-000">Visibilité Marketplace</h3><p>Une fois activées, les annonceurs peuvent voir vos audiences sur la plateforme et commencer à vous proposer des campagnes.</p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2563eb;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">8</div><div><h3 class="mt-0 text-grey-dk-000">Réception &amp; Négociation</h3><p>Lorsqu&#39;une campagne est proposée, tous vos utilisateurs reçoivent une notification.</p><div class="p-4 bg-grey-lt-000 rounded-1 border mb-3"><strong>Ne refusez pas, négociez !</strong><br> L&#39;objectif est de remplir votre inventaire. Plutôt que de refuser une offre : <ul><li><strong>💰 Prix trop bas ?</strong> Faites une contre-proposition tarifaire.</li><li><strong>📅 Dates indisponibles ?</strong> Proposez une autre période de diffusion.</li><li><strong>📦 Volume inadapté ?</strong> Ajustez la quantité proposée.</li></ul></div><p><strong>💬 Messagerie Intégrée :</strong> Utilisez le chat pour discuter avec l&#39;annonceur, argumenter votre prix ou demander des précisions.</p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#28a745;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">9</div><div><h3 class="mt-0 text-green-200">Validation Opérationnelle</h3><p>Une fois la campagne validée par les deux parties, on avance sur l&#39;opérationnel :</p><ul><li><strong>Asile Colis :</strong> Expédition des supports (respect du délai d&#39;ingestion).</li><li><strong>Digital :</strong> Transmission des assets créatifs et intégration.</li></ul></div></div><hr class="my-6"><h2 class="text-blue-200 mb-6">Phase 3 : Accélération &amp; Autonomie</h2><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2d6fd6;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3 class="mt-0 text-blue-200">Trade Marketing (Vos Marques)</h3><p>Ne dépendez pas uniquement des annonceurs externes. Soyez proactif avec vos propres fournisseurs !</p><div style="border:1px solid var(--vp-c-divider);padding:15px;border-radius:6px;background-color:#f0f8ff;"><strong>Le concept :</strong> Invitez les marques que vous distribuez à acheter de la visibilité chez vous (Asile, Email, Social) via getinside.<br><ul><li>✅ <strong>Simplification :</strong> Centralisez toute la gestion et la facturation au même endroit.</li><li>✅ <strong>Rentabilité :</strong> Générez des revenus additionnels sur des partenaires déjà acquis.</li></ul></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2d6fd6;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🤝</div><div><h3 class="mt-0 text-blue-200">Affiliation &amp; Parrainage</h3><p>Vous connaissez d&#39;autres marques ou e-commerçants ?</p><ul><li>Invitez-les à rejoindre la plateforme.</li><li>Touchez une commission sur leur activité.</li><li><a href="affiliation">Voir le programme d&#39;affiliation</a>.</li></ul></div></div>',19)])])}const m=i(o,[["render",r]]);export{g as __pageData,m as default};
